function Settings() {
  const queryClient = useQueryClient();
  const { data: settings = defaults } = useQuery({
    queryKey: ['settings'],
    queryFn: () => fetch('/api/settings').then(r => r.json())
  });

  const mutation = useMutation({
    mutationFn: (next: Settings) => fetch('/api/settings', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(next)
    }).then(r => { if (!r.ok) throw new Error('Save failed'); }),
    onMutate: async (next) => {
      await queryClient.cancelQueries({ queryKey: ['settings'] });
      const previous = queryClient.getQueryData<Settings>(['settings']);
      queryClient.setQueryData(['settings'], next);
      return { previous };
    },
    onError: (_e, _v, context) => {
      if (context?.previous) queryClient.setQueryData(['settings'], context.previous);
      toast.error('Save failed');
    }
  });

  const debouncedSave = useDebouncedCallback(mutation.mutate, 500);

  const update = (changes: Partial<Settings>) => {
    const next = { ...settings, ...changes };
    queryClient.setQueryData(['settings'], next);  // optimistic UI
    debouncedSave(next);
  };

  return <input value={settings.email} onChange={(e) => update({ email: e.target.value })} />;
}

